const iterations = $.steps.fetchMessages.response.iterations || [];
let emails = [];

iterations.forEach((iter, i) => {
  const resp = iter.getMessage ? iter.getMessage.response : null;
  if (!resp) return;
  const headers = (resp.payload && resp.payload.headers) || [];
  const subject = (headers.find(h => h.name === 'Subject') || {}).value || '';
  const from = (headers.find(h => h.name === 'From') || {}).value || '';
  emails.push({ index: i, id: resp.id || '', subject, from });
});

let emailsText = '';
emails.forEach((e, i) => { emailsText += (i + 1) + '. From: ' + e.from + ' | Subject: ' + e.subject + '\n'; });

return { emails, emailsText, count: emails.length };

const data = $.steps.compileForCategorization.output;

const prompt = 'You are an email organization specialist. Categorize each email into one of these categories: Work, Shopping, Newsletter, Personal, Finance, Travel, Social, Notification, Spam.

EMAILS TO CATEGORIZE:
' + data.emailsText + '

For each email, determine the most appropriate category based on the sender and subject. Return ONLY valid JSON:
{
  "categorized": [
    { "emailNumber": 1, "category": "Work", "priority": "high/medium/low", "suggestedAction": "read/archive/star/delete" }
  ],
  "summary": {
    "total": 0,
    "byCategory": { "Work": 0, "Shopping": 0, "Newsletter": 0 },
    "highPriority": 0
  }
}';

return { prompt };

let raw = $.steps.aiCategorize.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { categorized: [], summary: { total: 0, byCategory: {} } }; }

const ai = $.steps.parseAI.output;
const emails = $.steps.compileForCategorization.output.emails || [];
const summary = ai.summary || {};

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Gmail Inbox Organization Report', emoji: true } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Emails Processed:*\n' + (summary.total || emails.length) },
  { type: 'mrkdwn', text: '*High Priority:*\n' + (summary.highPriority || 0) }
] });
blocks.push({ type: 'divider' });

const byCategory = summary.byCategory || {};
let catText = '*By Category:*\n';
Object.keys(byCategory).forEach(cat => { catText += cat + ': ' + byCategory[cat] + '\n'; });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: catText } });

const categorized = ai.categorized || [];
const highPriority = categorized.filter(c => c.priority === 'high');
if (highPriority.length > 0) {
  let hpText = '*High Priority Emails:*\n';
  highPriority.forEach(hp => {
    const email = emails[hp.emailNumber - 1];
    if (email) { hpText += '- ' + email.subject + ' (from: ' + email.from.split('<')[0].trim() + ')\n'; }
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: hpText.slice(0, 1800) } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Organized ' + emails.length + ' emails with AI categorization' }] });
const fallback = 'Inbox organized: ' + emails.length + ' emails categorized. High priority: ' + (summary.highPriority || 0);
return { blocks, fallback };
